#!/usr/bin/env bash
set -euo pipefail
cd "$(dirname "${BASH_SOURCE[0]}")/.."
# Clean bytecode generated by previous test runs.
find . -path '*/__pycache__' -type d -prune -exec rm -rf {} + 2>/dev/null || true
fail=0
say(){ printf '[test] %s\n' "$*"; }
badflag='--video'"-bit-rate"

say 'bash syntax'
while IFS= read -r f; do bash -n "$f"; done < <(find . -type f \( -name '*.sh' -o -name 'androidlab.sh' -o -name 'install.sh' -o -name 'web-install.sh' \) | sort)

say 'no pycache packaged before tests'
if find . -path '*/__pycache__/*' -print -quit | grep -q .; then echo 'pycache found before tests' >&2; fail=1; fi

say 'python syntax'
PYTHONDONTWRITEBYTECODE=1 python3 -m py_compile manager/app.py

say 'clean-stale script present'
[[ -x scripts/clean-stale-files.sh ]] || { echo 'missing clean-stale-files.sh' >&2; fail=1; }

say 'scrcpy unsupported flag absent'
if grep -RIn --exclude='regression-test.sh' -- "$badflag" .; then
  echo "found unsupported scrcpy flag" >&2
  fail=1
fi

say 'rendered manager HTML smoke test'
TMP="$(mktemp -d)"
mkdir -p "$TMP/lab/config" "$TMP/lab/uploads" "$TMP/fake"
cat > "$TMP/lab/config/instances.tsv" <<'EOF'
old-headless	headless	13555	33	google_apis	2026-01-01
panel	novnc	13556	13080	33	google_apis	2026-01-01
EOF
cat > "$TMP/fake/flask.py" <<'PY'
class _Req:
    host='server:18080'
    form={}
    files={}
    authorization=None
request=_Req()
class Response:
    def __init__(self,*a,**k): pass
class Flask:
    def __init__(self,*a,**k): pass
    def before_request(self,f): return f
    def get(self,*a,**k): return lambda f:f
    def post(self,*a,**k): return lambda f:f
    def run(self,*a,**k): pass
PY
PYTHONDONTWRITEBYTECODE=1 LAB_HOME="$TMP/lab" PYTHONPATH="$TMP/fake:$PWD" python3 - <<'PY'
import manager.app as app
html=app.index()
assert 'Android 13 / API 33' in html, 'missing Android version preset list'
assert 'Android 16 / API 36' in html, 'missing Android 16 preset'
assert '--bit-rate 4M' in html, 'missing old-compatible scrcpy flag'
assert ('--video' + '-bit-rate') not in html, 'bad scrcpy flag rendered'
assert 'http://server:33/vnc.html' not in html, 'old record parsed API as noVNC port'
assert 'http://server:13080/vnc.html' in html, 'valid noVNC URL missing'
assert 'Open with controls' in html, 'controlled noVNC link missing'
assert '/novnc/panel' in html, 'controlled noVNC wrapper URL missing'
assert 'resize=off' in html, 'noVNC 1:1 link missing'
assert 'resize=scale' in html, 'noVNC scaled link missing'
assert 'resize=remote' in html, 'noVNC remote resize link missing'
assert 'table-wrap' in html, 'responsive table wrapper missing'
assert '<th>Status</th>' in html, 'status column missing'
assert 'power-actions' in html, 'power controls missing from cards'
assert "data-testid='spawn-device-profile'" in html, 'spawn phone model selector test id missing'
assert "data-testid='manual-device-profile'" in html, 'manual phone model selector test id missing'
assert "data-testid='instance-card-old-headless'" in html, 'instance card missing'
assert '<th>Device</th>' in html, 'device column missing'
assert 'Phone model' in html, 'phone model selector missing'
assert 'Pixel 6' in html, 'Pixel 6 option missing'
assert 'Runtime profiles' in html, 'runtime profiles section missing'
assert 'Refresh SDK device-profile list' in html, 'device profile refresh missing'
assert 'pixel_6' in html, 'pixel_6 device id missing'
assert "value='start'" in html or 'value="start"' in html, 'start lifecycle button missing'
assert "value='stop'" in html or 'value="stop"' in html, 'stop lifecycle button missing'
assert "data-testid='power-start-old-headless'" in html, 'start power test id missing'
assert "data-testid='power-stop-old-headless'" in html, 'stop power test id missing'
assert 'Phone model selector enabled' in html, 'feature proof banner missing'
assert "id='view-spawn'" in html, 'spawn view section missing'
assert "id='view-profiles'" in html, 'profiles view section missing'
assert "id='view-instances'" in html, 'instances view section missing'
assert "class='readable-table'" in html, 'readable table class missing'
assert 'Client scrcpy command</th>' not in html, 'long command column still present in table header'
assert 'status-badge' in html, 'status badge missing'
assert 'Apply size profile' in html, 'noVNC resize action missing'
assert 'Build/update image before spawn' in html, 'build-before-spawn checkbox missing'
assert 'background progress' in html, 'background progress label missing'
assert 'Apply HW + restart' in html, 'apply HW action missing'
assert 'CPU cores' in html and 'RAM MB' in html and 'Partition MB' in html, 'HW form fields missing'
assert '<th>HW</th>' in html, 'HW table column missing'
assert 'Full HD phone' in html, 'Full HD profile missing'
assert "class='hero'" in html or 'class="hero"' in html, 'modern hero missing'
assert '/static/app.js' in html and '/static/app.css' in html, 'static assets missing from rendered page'
assert '<select name=\'preset\'>' in html or '<select name="preset">' in html, 'preset select missing'
# Simulate web POST actions without a real Podman runtime.
calls=[]
def fake_run(args, env_extra=None):
    calls.append((args, env_extra))
    return 'RUN ' + ' '.join(args)
app.run = fake_run
app.image_exists = lambda api, target, mode='headless': True
app.request.form = {'name':'old-headless','op':'start'}
assert 'RUN start old-headless' in app.action(), 'web Start action did not call androidlab start'
app.request.form = {'name':'old-headless','op':'stop'}
assert 'RUN stop old-headless' in app.action(), 'web Stop action did not call androidlab stop'
app.request.form = {'name':'android-pixel6','mode':'headless','preset':'33|google_apis','device_profile':'pixel_6','device_custom':'','cpu_cores':'4','ram_mb':'8192','vm_heap_mb':'512','partition_size':'8192'}
assert 'RUN spawn android-pixel6 headless 33 google_apis pixel_6' in app.spawn(), 'web Spawn did not pass pixel_6 device profile'
assert calls[-1][1]['CPU_CORES']=='4' and calls[-1][1]['RAM_MB']=='8192', 'web Spawn did not pass HW env'
app.request.form = {'name':'old-headless','cpu_cores':'4','ram_mb':'8192','vm_heap_mb':'512','partition_size':'8192'}
assert 'RUN apply-hw old-headless' in app.apply_hw(), 'web Apply HW did not call androidlab apply-hw'
assert calls[-1][1]['CPU_CORES']=='4' and calls[-1][1]['PARTITION_SIZE']=='8192', 'web Apply HW did not pass HW env'
started=[]
def fake_start_job(title, steps):
    started.append((title, steps))
    return 'job123'
app.start_background_job = fake_start_job
app.request.form = {'name':'android-pixel6-bg','mode':'headless','preset':'36|google_apis','device_profile':'pixel_6','device_custom':'','cpu_cores':'4','ram_mb':'8192','vm_heap_mb':'512','partition_size':'8192','build_first':'1'}
job_html = app.spawn()
assert 'job_status/job123' in job_html and 'background job' in job_html, 'build-before-spawn did not return progress page'
assert started and started[-1][1][0]['args'] == ['build-api','36','google_apis','x86_64'], 'async spawn did not queue build step'
assert started[-1][1][1]['args'] == ['spawn','android-pixel6-bg','headless','36','google_apis','pixel_6'], 'async spawn did not queue spawn step'
assert started[-1][1][1]['env']['CPU_CORES'] == '4', 'async spawn did not pass HW env'
novnc_html = app.novnc_session('panel')
assert 'noVNC session: panel' in novnc_html, 'controlled noVNC route did not render session title'
assert 'data-instance-name="panel"' in novnc_html, 'controlled noVNC route did not pass instance name to template'
assert 'http://server:13080/vnc.html' in novnc_html, 'controlled noVNC route did not render direct noVNC src'
PY
rm -rf "$TMP"

say 'copy fallback present'
grep -q 'document.execCommand' manager/static/app.js || { echo 'missing execCommand fallback' >&2; fail=1; }
grep -q 'window.prompt' manager/static/app.js || { echo 'missing prompt fallback' >&2; fail=1; }

say 'API presets present'
for api in 33 34 35 36; do grep -q "'$api'" manager/definitions.py || { echo "missing API $api preset" >&2; fail=1; }; done

say 'manager CSRF support present'
grep -q 'CSRF_TOKEN' manager/app.py || { echo 'missing CSRF token support' >&2; fail=1; }
