grep -q 'ANDROIDLAB_MANAGER_LOCAL_HOST_DEFAULT' androidlab.sh || { echo 'base install does not use central local-safe manager host default' >&2; fail=1; }

say 'manager env file install simulation'
SIMENV="$(mktemp -d)"
mkdir -p "$SIMENV/bin" "$SIMENV/home" "$SIMENV/lab"
cat > "$SIMENV/bin/systemctl" <<'SH'
#!/usr/bin/env bash
exit 0
