chmod +x "$SIMENV/bin/systemctl"
HOME="$SIMENV/home" LAB_HOME="$SIMENV/lab" PATH="$SIMENV/bin:$PATH" scripts/install-manager-service.sh 0.0.0.0 18080 token123 server.internal >/tmp/androidlab-manager-service-test.out
[[ -s "$SIMENV/lab/config/manager.env" ]] || { echo 'install-manager-service did not create manager.env' >&2; fail=1; }
grep -q 'MANAGER_TOKEN=token123' "$SIMENV/lab/config/manager.env" || { echo 'manager.env missing token' >&2; fail=1; }
grep -q 'PUBLIC_HOST=server.internal' "$SIMENV/lab/config/manager.env" || { echo 'manager.env missing public host' >&2; fail=1; }
grep -q 'EnvironmentFile=-' "$SIMENV/home/.config/systemd/user/androidlab-manager.service" || { echo 'service missing optional EnvironmentFile' >&2; fail=1; }
grep -q 'ExecStartPre=.*ensure-manager-env.sh' "$SIMENV/home/.config/systemd/user/androidlab-manager.service" || { echo 'service missing env repair ExecStartPre' >&2; fail=1; }
