assert web.index('ensure-manager-env.sh') < web.index('./androidlab.sh'), 'web-install creates manager.env after androidlab install'
PYORDER

say 'no unsafe local same-line arithmetic'
if grep -RIn 'local p="\$1" end=\$((p+1000))' scripts; then echo 'unsafe local/end assignment found' >&2; fail=1; fi

