#!/usr/bin/env bash
set -euo pipefail
if [[ "${1:-}" == "pod" && "${2:-}" == "ls" ]]; then echo android-emu13-nostore; exit 0; fi
if [[ "${1:-}" == "container" && "${2:-}" == "exists" ]]; then [[ "${3:-}" == "android-emu13-nostore-emulator" ]]; exit $?; fi
if [[ "${1:-}" == "port" ]]; then
  if [[ "${2:-}" == "android-emu13-nostore-emulator" && "${3:-}" == "5555/tcp" ]]; then echo "0.0.0.0:13555"; exit 0; fi
  if [[ "${2:-}" == "android-emu13-nostore-emulator" && "${3:-}" == "6080/tcp" ]]; then exit 0; fi
fi
if [[ "${1:-}" == "pod" && "${2:-}" == "inspect" ]]; then exit 0; fi
if [[ "${1:-}" == "inspect" && "${2:-}" == "android-emu13-nostore-emulator" ]]; then
  joined="$*"
  case "$joined" in
    *Config.Env*) echo "ANDROID_API=33"; echo "ANDROID_TARGET=google_apis"; exit 0 ;;
    *ImageName*) echo "localhost/android-emulator-headless:api33-google_apis-x86_64"; exit 0 ;;
    *Created*) echo "2026-06-15T20:03:01+02:00"; exit 0 ;;
  esac
fi
exit 0
POD
